class Solution {
public:
    int maxValue(int n, int index, int maxSum) {
        int left = 0, right = maxSum;
        while (left < right) {
            int mid = left + (right + 1) / 2;
            long long sum = 0;
            sum += (long long)(mid + (mid - min(mid - 1, index)));
            sum += (long long)(mid + (mid - min(mid - 1, n - index - 1)));
            sum -= 1;
            if (sum > maxSum) {
                right = mid - 1;
            } else {
                left = mid;
            }
        }
        return left;
    }
};
